const sd = $getWorkflowStaticData('global');
if (!sd.chats) sd.chats = {};
const inp = $input.first().json;
const isCb = !!inp.callback_query;
const chatId = isCb ? inp.callback_query.message.chat.id : inp.message?.chat?.id;
const text = isCb ? '' : (inp.message?.text || '').trim();
const cb = isCb ? inp.callback_query.data : '';
const st = sd.chats[chatId] || {};
const r = { action:'reply', chatId, text:'', kb:null, title:'', type:'', subType:'', raw:'', cId:'', ratio:'' };

const MENU = [[{text:'Buat Konten',callback_data:'m_create'},{text:'Cek Status',callback_data:'m_status'}],[{text:'Submit Review',callback_data:'m_submit'},{text:'Prompt Thumbnail',callback_data:'m_thumb'}],[{text:'Buka Web Adably',url:'https://adably.id/admin'},{text:'Bantuan',callback_data:'m_help'}]];
const TYPES = [[{text:'QNA',callback_data:'t_QNA'},{text:'Artikel',callback_data:'t_ARTICLE'}],[{text:'Pembelajaran',callback_data:'t_PEMBELAJARAN'},{text:'Kisah',callback_data:'t_KISAH'}],[{text:'Menu',callback_data:'m_main'}]];
const KISAH = [[{text:'Sirah Nabawiyah',callback_data:'k_SIRAH'}],[{text:'Qashashul Anbiya',callback_data:'k_QASHASH'}],[{text:'Teladan Sahabat',callback_data:'k_TELADAN'}],[{text:'Cerita Fiksi',callback_data:'k_FIKSI'}],[{text:'Kembali',callback_data:'m_create'}]];
const RATIO = [[{text:'16:9 Website',callback_data:'r_16:9'}],[{text:'1:1 IG/FB',callback_data:'r_1:1'}],[{text:'4:5 IG Optimal',callback_data:'r_4:5'}],[{text:'Menu',callback_data:'m_main'}]];

if (isCb) {
  switch(cb) {
    case 'm_main': r.text='Menu Utama - Pilih menu:'; r.kb=MENU; break;
    case 'm_create': r.text='Pilih tipe konten:'; r.kb=TYPES; break;
    case 'm_status': sd.chats[chatId]={step:'wait_status_id'}; r.text='Ketik ID konten:'; break;
    case 'm_submit': sd.chats[chatId]={step:'wait_submit_id'}; r.text='Ketik ID konten yang ingin diajukan review:'; break;
    case 'm_thumb': r.text='Pilih rasio thumbnail:'; r.kb=RATIO; break;
    case 'm_help': r.text='Panduan Adably Bot\n\n1. Klik Buat Konten lalu pilih tipe\n2. Ketik judul lalu bot kirim prompt\n3. Copy prompt lalu paste ke Gemini\n4. Kirim hasil Gemini ke bot\n5. Bot simpan otomatis ke DRAFT\n6. Klik Submit Review'; r.kb=[[{text:'Menu',callback_data:'m_main'}]]; break;
    case 't_QNA': case 't_ARTICLE': case 't_PEMBELAJARAN': {
      const tp=cb.replace('t_',''); sd.chats[chatId]={step:'wait_title',type:tp};
      r.text='Tipe: '+tp+'\n\nKetik judul konten:'; break; }
    case 't_KISAH': r.text='Pilih sub-tipe Kisah:'; r.kb=KISAH; break;
    case 'k_SIRAH': case 'k_QASHASH': case 'k_TELADAN': case 'k_FIKSI': {
      const ks=cb.replace('k_',''); sd.chats[chatId]={step:'wait_title',type:'KISAH',sub:ks};
      r.text='Kisah: '+ks+'\n\nKetik judul kisah:'; break; }
    case 'r_16:9': case 'r_1:1': case 'r_4:5': {
      const rt=cb.replace('r_',''); sd.chats[chatId]={step:'wait_thumb_title',ratio:rt};
      r.text='Rasio: '+rt+'\n\nKetik judul/tema thumbnail:'; break; }
    default:
      if(cb.startsWith('submit_')){r.action='submit';r.cId=cb.replace('submit_','');}
      else if(cb.startsWith('status_')){r.action='status';r.cId=cb.replace('status_','');}
      else{r.text='Perintah tidak dikenali';r.kb=MENU;}
  }
} else if (text.startsWith('/start')) {
  r.text='Assalamualaikum!\n\nSaya Adably Content Bot - Asisten pembuatan konten islami anak.\n\nPilih menu:'; r.kb=MENU;
} else if (st.step === 'wait_title') {
  r.action='gen_prompt'; r.type=st.type; r.subType=st.sub||''; r.title=text;
  sd.chats[chatId] = {step:'wait_content',type:st.type,sub:st.sub,title:text};
} else if (st.step === 'wait_content') {
  r.action='save'; r.type=st.type; r.subType=st.sub||''; r.title=st.title; r.raw=text;
  delete sd.chats[chatId];
} else if (st.step === 'wait_thumb_title') {
  r.action='gen_thumb'; r.ratio=st.ratio; r.title=text;
  delete sd.chats[chatId];
} else if (st.step === 'wait_status_id') {
  r.action='status'; r.cId=text.trim(); delete sd.chats[chatId];
} else if (st.step === 'wait_submit_id') {
  r.action='submit'; r.cId=text.trim(); delete sd.chats[chatId];
} else {
  r.text='Gunakan menu di bawah:'; r.kb=MENU;
}

if (r.action === 'reply' && !r.text) { r.text='Pilih menu:'; r.kb=MENU; }

return [{json:r}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const prompt = res.prompt || 'Error generating prompt';
const chatId = prev.chatId;
const msgs = [];
const header = 'Prompt ' + prev.type + ' - ' + prev.title + '\n\n';
const footer = '\n\nCopy prompt di atas lalu paste ke Gemini. Kirim hasilnya ke sini.';
const full = header + prompt + footer;
if (full.length <= 4096) {
  msgs.push({ chatId, text: full, kb: [[{text:'Batalkan',callback_data:'m_main'}]] });
} else {
  const chunkSize = 4000;
  for (let i = 0; i < full.length; i += chunkSize) {
    const chunk = full.substring(i, i + chunkSize);
    const isLast = (i + chunkSize) >= full.length;
    msgs.push({ chatId, text: chunk, kb: isLast ? [[{text:'Batalkan',callback_data:'m_main'}]] : null });
  }
}
return msgs.map(m => ({ json: m }));

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const prompt = res.prompt || 'Error';
const text = 'Prompt Thumbnail ' + prev.ratio + ' - ' + prev.title + '\n\n' + prompt + '\n\nCopy lalu paste ke AI image generator. Upload manual di web Adably.';
const kb = [[{text:'Rasio Lain',callback_data:'m_thumb'},{text:'Menu',callback_data:'m_main'}]];
return [{json:{chatId:prev.chatId,text:text.length>4096?text.substring(0,4090)+'...':text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const ok = res.success;
const id = res.data?.id || '';
const kb = ok ? [[{text:'Submit Review',callback_data:'submit_'+id},{text:'Status',callback_data:'status_'+id}],[{text:'Buka Editor',url:'https://adably.id/admin/editor?id='+id},{text:'Menu',callback_data:'m_main'}]] : [[{text:'Menu',callback_data:'m_main'}]];
const text = ok ? 'Konten tersimpan!\n\nID: '+id+'\nJudul: '+(res.data?.title||'')+'\nStatus: '+(res.data?.status||'')+'\nTipe: '+(res.data?.type||'') : 'Gagal menyimpan: '+(res.message||'Error');
return [{json:{chatId:prev.chatId,text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const text = res.success ? 'Berhasil! ' + (res.message||'') : 'Gagal submit: '+(res.message||'Error');
const kb = [[{text:'Cek Status',callback_data:'status_'+prev.cId},{text:'Menu',callback_data:'m_main'}]];
return [{json:{chatId:prev.chatId,text,kb}}];

const prev = $('Main Logic').first().json;
const res = $input.first().json;
const d = res.data || {};
const text = res.success ? 'Status Konten

ID: '+(d.id||'-')+'
Judul: '+(d.title||'-')+'
Tipe: '+(d.type||'-')+'
Status: '+(d.status||'-')+'
Update: '+(d.updatedAt?.substring(0,10)||'-')+'
Thumbnail: '+(d.thumbnailUrl?'Ada':'Belum') : 'Error: '+(res.message||'Tidak ditemukan');
const kb = res.success ? [[{text:'Submit',callback_data:'submit_'+d.id},{text:'Editor',url:'https://adably.id/admin/editor?id='+d.id}],[{text:'Menu',callback_data:'m_main'}]] : [[{text:'Menu',callback_data:'m_main'}]];
return [{json:{chatId:prev.chatId,text,kb}}];
